import { useEffect, useState } from "react";
import API from "../api";

const Profile = () => {
  const [user, setUser] = useState(null);
  const [editing, setEditing] = useState(false);
  const [formData, setFormData] = useState({});
  const [passwordData, setPasswordData] = useState({ currentPassword: "", newPassword: "" });
  const [message, setMessage] = useState("");
  const [error, setError] = useState("");

  useEffect(() => {
    const fetchProfile = async () => {
      try {
        const res = await API.getUserProfile();
        setUser(res.data.user);
        setFormData({
          firstName: res.data.user.firstName || "",
          lastName: res.data.user.lastName || "",
          contactNumber: res.data.user.contactNumber || "",
          collegeName: res.data.user.collegeName || "",
          interests: res.data.user.interests || [],
          followedOrganisers: res.data.user.followedOrganisers || [],
        });
      } catch (err) {
        console.error(err);
        setError("Failed to load profile");
      }
    };
    fetchProfile();
  }, []);

  const handleChange = (e) => {
    const { name, value } = e.target;
    setFormData({ ...formData, [name]: value });
  };

  const handlePasswordChange = (e) => {
    const { name, value } = e.target;
    setPasswordData({ ...passwordData, [name]: value });
  };

  const handleUpdate = async (e) => {
    e.preventDefault();
    setMessage(""); setError("");
    try {
      const res = await API.updateUserProfile(formData);
      setUser(res.data.user);
      setEditing(false);
      setMessage("Profile updated successfully!");
    } catch (err) {
      console.error(err);
      setError(err.response?.data?.message || "Failed to update profile");
    }
  };

  const handlePasswordSubmit = async (e) => {
    e.preventDefault();
    setMessage(""); setError("");
    try {
      await API.put("/users/profile/password", passwordData);
      setPasswordData({ currentPassword: "", newPassword: "" });
      setMessage("Password updated successfully!");
    } catch (err) {
      console.error(err);
      setError(err.response?.data?.message || "Failed to update password");
    }
  };

  if (!user) return <p style={{ textAlign: "center" }}>Loading profile...</p>;

  return (
    <div style={styles.container}>
      <h2>My Profile</h2>
      {message && <p style={styles.success}>{message}</p>}
      {error && <p style={styles.error}>{error}</p>}

      {!editing ? (
        <div style={styles.profileBox}>
          <p><strong>First Name:</strong> {user.firstName}</p>
          <p><strong>Last Name:</strong> {user.lastName}</p>
          <p><strong>Email:</strong> {user.email}</p>
          <p><strong>Participant Type:</strong> {user.participantType}</p>
          <p><strong>Contact Number:</strong> {user.contactNumber || "-"}</p>
          <p><strong>College:</strong> {user.collegeName || "-"}</p>
          <p><strong>Interests:</strong> {user.interests?.join(", ") || "-"}</p>
          <p><strong>Followed Clubs:</strong> {user.followedOrganisers?.map(c => c.name).join(", ") || "-"}</p>

          <button style={styles.button} onClick={() => setEditing(true)}>Edit Profile</button>
        </div>
      ) : (
        <form onSubmit={handleUpdate} style={styles.form}>
          <input type="text" name="firstName" value={formData.firstName} onChange={handleChange} placeholder="First Name" required style={styles.input}/>
          <input type="text" name="lastName" value={formData.lastName} onChange={handleChange} placeholder="Last Name" required style={styles.input}/>
          <input type="text" name="contactNumber" value={formData.contactNumber} onChange={handleChange} placeholder="Contact Number" style={styles.input}/>
          <input type="text" name="collegeName" value={formData.collegeName} onChange={handleChange} placeholder="College/Organization" style={styles.input}/>
          <input type="text" name="interests" value={formData.interests} onChange={handleChange} placeholder="Interests (comma separated)" style={styles.input}/>
          <input type="text" name="followedOrganisers" value={formData.followedOrganisers} onChange={handleChange} placeholder="Followed Clubs (comma separated)" style={styles.input}/>

          <div style={{ display: "flex", gap: "10px" }}>
            <button type="submit" style={styles.button}>Save</button>
            <button type="button" style={styles.cancelBtn} onClick={() => setEditing(false)}>Cancel</button>
          </div>
        </form>
      )}

      <h3 style={{ marginTop: "30px" }}>Change Password</h3>
      <form onSubmit={handlePasswordSubmit} style={styles.form}>
        <input type="password" name="currentPassword" value={passwordData.currentPassword} onChange={handlePasswordChange} placeholder="Current Password" required style={styles.input}/>
        <input type="password" name="newPassword" value={passwordData.newPassword} onChange={handlePasswordChange} placeholder="New Password" required style={styles.input}/>
        <button type="submit" style={styles.button}>Update Password</button>
      </form>
    </div>
  );
};

const styles = {
  container: { maxWidth: "600px", margin: "60px auto", padding: "25px", border: "1px solid #ddd", borderRadius: "8px", backgroundColor: "#fff" },
  profileBox: { marginTop: "20px" },
  form: { display: "flex", flexDirection: "column", gap: "15px", marginTop: "20px" },
  input: { padding: "10px", borderRadius: "5px", border: "1px solid #ccc" },
  button: { padding: "8px 14px", backgroundColor: "#007bff", color: "white", border: "none", borderRadius: "5px", cursor: "pointer" },
  cancelBtn: { padding: "8px 14px", backgroundColor: "#6c757d", color: "white", border: "none", borderRadius: "5px", cursor: "pointer" },
  success: { color: "green" },
  error: { color: "red" },
};

export default Profile;
